"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[48389],{6873:(e,l,t)=>{t.r(l),t.d(l,{data:()=>i});const i={key:"v-793beb49",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/02.%E6%94%B9%E5%8F%98%E5%89%8D%E7%BC%80.html",title:"自定义控件(二)-改变前缀",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/02.改变前缀.md"}},31759:(e,l,t)=>{t.r(l),t.d(l,{default:()=>n});const i=(0,t(57293).uE)('<h1 id="自定义控件-二-改变前缀" tabindex="-1"><a class="header-anchor" href="#自定义控件-二-改变前缀" aria-hidden="true">#</a> 自定义控件(二)-改变前缀</h1><p>把自定义控件添加到页面上，查看源代码发现添加了以下两行代码</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;%@ Register Assembly=&quot;kjlx.BLL&quot; Namespace=&quot;kjlx.BLL.HelloWorld&quot; TagPrefix=&quot;cc1&quot; %&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>   &lt;cc1:HelloWorld ID=&quot;HelloWorld1&quot; runat=&quot;server&quot;&gt;\n        &lt;/cc1:HelloWorld&gt;cc1:HelloWorld ID=&quot;HelloWorld1&quot; runat=&quot;server&quot;&gt;\n        &lt;/cc1:HelloWorld&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>第一行TagPrefix属性对应后面一行控件声明中的前缀，如果觉得cc1没个性，可以改成其他值</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;%@ Register Assembly=&quot;kjlx.BLL&quot; Namespace=&quot;kjlx.BLL.HelloWorld&quot; TagPrefix=&quot;pzy&quot; %&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;pzy:HelloWorld ID=&quot;HelloWorld1&quot; runat=&quot;server&quot;&gt;\n        &lt;/pzy:HelloWorld&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>不过这种修改只对当前页面有效，如果有多张页面引用,这样改就会很繁琐。在web.config的system.web节中添加如下代码可以一次性解决。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>    &lt;system.web&gt;\n        &lt;compilation debug=&quot;false&quot; targetFramework=&quot;4.0&quot; /&gt;\n        &lt;pages&gt;\n            &lt;controls&gt;\n                &lt;add assembly=&quot;kjlx.BLL&quot; namespace=&quot;kjlx.BLL.HelloWorld&quot; tagPrefix=&quot;sc&quot;/&gt;\n            &lt;/controls&gt;\n        &lt;/pages&gt;\n    &lt;/system.web&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>assembly和namespace参考前面第一行代码,TagPrefix为自定义的前缀名</p><p>在web.config中定义之后添加控件就不会添加第一行代码，只会添加第二行代码</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;%@ Page Language=&quot;C#&quot; AutoEventWireup=&quot;true&quot; CodeFile=&quot;HelloWorld.aspx.cs&quot; Inherits=&quot;HelloWorld&quot; %&gt;\n&lt;!DOCTYPE html PUBLIC &quot;-//W3C//DTD XHTML 1.0 Transitional//EN&quot; &quot;http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd&quot;&gt;\n\n\n&lt;html xmlns=&quot;http://www.w3.org/1999/xhtml&quot;&gt;\n&lt;head runat=&quot;server&quot;&gt;\n    &lt;title&gt;&lt;/title&gt;\n&lt;/head&gt;\n&lt;body&gt;\n    &lt;form id=&quot;form1&quot; runat=&quot;server&quot;&gt;\n    &lt;div&gt;\n        &lt;sc:HelloWorld ID=&quot;HelloWorld1&quot; runat=&quot;server&quot;&gt;\n        &lt;/sc:HelloWorld&gt;\n    &lt;/div&gt;\n    &lt;/form&gt;\n&lt;/body&gt;\n&lt;/html&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p>',17),s={},n=(0,t(63243).Z)(s,[["render",function(e,l){return i}]])},63243:(e,l)=>{l.Z=(e,l)=>{const t=e.__vccOpts||e;for(const[e,i]of l)t[e]=i;return t}}}]);